import{_ as a,o as t,c as n,ag as r}from"./chunks/framework.CvgP6Fyv.js";const m=JSON.parse('{"title":"Je bedrijf instellen","description":"","frontmatter":{},"headers":[],"relativePath":"nl/getting-started/company-setup.md","filePath":"nl/getting-started/company-setup.md"}'),i={name:"nl/getting-started/company-setup.md"};function o(l,e,s,d,u,c){return t(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="je-bedrijf-instellen" tabindex="-1">Je bedrijf instellen <a class="header-anchor" href="#je-bedrijf-instellen" aria-label="Permalink to &quot;Je bedrijf instellen&quot;">​</a></h1><p>Voordat je facturen kunt versturen, moet je je bedrijfsinformatie configureren. Deze gegevens verschijnen op je facturen, offertes en andere documenten.</p><h2 id="bedrijfsinformatie" tabindex="-1">Bedrijfsinformatie <a class="header-anchor" href="#bedrijfsinformatie" aria-label="Permalink to &quot;Bedrijfsinformatie&quot;">​</a></h2><p>Navigeer naar <strong>Bedrijf</strong> in de zijbalk om je bedrijfsinstellingen te openen.</p><h3 id="verplichte-velden" tabindex="-1">Verplichte velden <a class="header-anchor" href="#verplichte-velden" aria-label="Permalink to &quot;Verplichte velden&quot;">​</a></h3><p>Deze velden zijn nodig om facturen te versturen:</p><ul><li><strong>Bedrijfsnaam</strong> — Je geregistreerde handelsnaam</li><li><strong>Adres</strong> — Straat, postcode en plaats (adresaanvulling is beschikbaar)</li><li><strong>E-mail</strong> — Je zakelijke contacte-mail</li></ul><h3 id="aanbevolen-velden" tabindex="-1">Aanbevolen velden <a class="header-anchor" href="#aanbevolen-velden" aria-label="Permalink to &quot;Aanbevolen velden&quot;">​</a></h3><p>Deze worden sterk aanbevolen voor professionele facturen en wettelijke compliance:</p><ul><li><strong>BTW-nummer</strong> — Je BTW-registratienummer (bijv. NL123456789B01)</li><li><strong>KVK-nummer</strong> — Je bedrijfsregistratienummer</li><li><strong>IBAN</strong> — Je bankrekeningnummer waarnaar klanten moeten betalen</li><li><strong>Telefoonnummer</strong> — Zakelijk contactnummer</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>In veel landen zijn BTW-nummer en KVK-nummer wettelijk verplicht op facturen. Zorg dat deze zijn ingevuld voordat je je eerste factuur verstuurt.</p></div><h2 id="huisstijl" tabindex="-1">Huisstijl <a class="header-anchor" href="#huisstijl" aria-label="Permalink to &quot;Huisstijl&quot;">​</a></h2><h3 id="bedrijfslogo" tabindex="-1">Bedrijfslogo <a class="header-anchor" href="#bedrijfslogo" aria-label="Permalink to &quot;Bedrijfslogo&quot;">​</a></h3><p>Upload je bedrijfslogo om het te laten verschijnen op:</p><ul><li>Facturen en offertes (PDF)</li><li>E-mailcommunicatie</li><li>Je openbare bedrijfspagina</li><li>Het klantbetaalportaal</li></ul><p>Ondersteunde formaten: PNG, JPG, SVG. Gebruik voor het beste resultaat een afbeelding met hoge resolutie en een transparante achtergrond.</p><h3 id="kleurenschema" tabindex="-1">Kleurenschema <a class="header-anchor" href="#kleurenschema" aria-label="Permalink to &quot;Kleurenschema&quot;">​</a></h3><p>Pas de accentkleur aan die wordt gebruikt op je facturen en documenten, zodat deze past bij je huisstijl.</p><h2 id="financiele-standaardwaarden" tabindex="-1">Financiele standaardwaarden <a class="header-anchor" href="#financiele-standaardwaarden" aria-label="Permalink to &quot;Financiele standaardwaarden&quot;">​</a></h2><p>Stel standaardwaarden in die gelden voor nieuwe facturen en offertes:</p><ul><li><strong>Valuta</strong> — Je standaardvaluta (standaard EUR)</li><li><strong>Betalingstermijn</strong> — Standaard aantal dagen tot een factuur vervalt (bijv. 14 of 30 dagen)</li><li><strong>Factuurnummering</strong> — Pas het formaat van je factuurnummers aan <ul><li>Voorvoegsel (bijv. <code>INV-</code> of <code>2024-</code>)</li><li>Startnummer</li><li>Automatische ophoging</li></ul></li></ul><h3 id="voorbeelden-factuurnummering" tabindex="-1">Voorbeelden factuurnummering <a class="header-anchor" href="#voorbeelden-factuurnummering" aria-label="Permalink to &quot;Voorbeelden factuurnummering&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Formaat</th><th>Voorbeeld</th></tr></thead><tbody><tr><td>Eenvoudig</td><td><code>001</code>, <code>002</code>, <code>003</code></td></tr><tr><td>Met voorvoegsel</td><td><code>INV-001</code>, <code>INV-002</code></td></tr><tr><td>Op jaarbasis</td><td><code>2024-001</code>, <code>2024-002</code></td></tr></tbody></table><p>De nummeringsopties en het formaat kunnen op elk moment worden aangepast. Bestaande factuurnummers worden nooit gewijzigd.</p><h2 id="pdf-sjabloon" tabindex="-1">PDF-sjabloon <a class="header-anchor" href="#pdf-sjabloon" aria-label="Permalink to &quot;PDF-sjabloon&quot;">​</a></h2><p>MyCompanyDesk genereert automatisch professionele PDF-facturen. Je kunt de lay-out aanpassen met de <strong>PDF-editor</strong>:</p><ul><li>Veldposities en zichtbaarheid aanpassen</li><li>Kiezen welke informatie wordt weergegeven</li><li>Lettertypen en grootte aanpassen</li><li>Wijzigingen in realtime bekijken met een voorbeeldfactuur</li></ul><p>Open de PDF-editor via <strong>Bedrijf &gt; PDF-editor</strong> of via het huisstijlgedeelte.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>PDF-aanpassing voorbij de basisinstellingen vereist het <strong>Pro</strong>-abonnement of hoger.</p></div><h2 id="functiemodules-aan-uit" tabindex="-1">Functiemodules aan/uit <a class="header-anchor" href="#functiemodules-aan-uit" aria-label="Permalink to &quot;Functiemodules aan/uit&quot;">​</a></h2><p>MyCompanyDesk heeft optionele modules die je kunt in- of uitschakelen afhankelijk van je bedrijfsbehoeften:</p><ul><li><strong>Objecten / Activa</strong> — Voor verhuur- en activabeheer</li><li><strong>Contracten</strong> — Voor terugkerende service- of huurcontracten</li><li><strong>Projecten</strong> — Voor projectmatig werken en tijdregistratie</li><li><strong>Offertes</strong> — Voor het versturen van offertes</li><li><strong>Verlegde BTW</strong> — Voor intra-EU B2B-transacties</li><li><strong>AI-suggesties</strong> — Voor slimme categorisatie en aanbevelingen</li><li><strong>Bonnen scannen</strong> — Voor OCR-gebaseerde uitgaveninvoer</li><li><strong>Tekstcontrole</strong> — Voor grammatica- en spellingcontrole in je documenten</li></ul><p>Het uitschakelen van een module verbergt deze uit de navigatie, zodat je werkruimte overzichtelijk blijft.</p><h2 id="volgende-stappen" tabindex="-1">Volgende stappen <a class="header-anchor" href="#volgende-stappen" aria-label="Permalink to &quot;Volgende stappen&quot;">​</a></h2><p>Je bedrijf is ingesteld. Tijd om <a href="/nl/getting-started/first-invoice">je eerste factuur te maken</a>.</p>',35)])])}const h=a(i,[["render",o]]);export{m as __pageData,h as default};
